--
-- Name: tax_bridge_audit_logs; Type: TABLE; Schema: sales; Owner: -
--

CREATE TABLE sales.tax_bridge_audit_logs (
    id bigint NOT NULL,
    company_id bigint NOT NULL,
    branch_id bigint,
    document_id bigint,
    document_kind character varying(50),
    document_series character varying(10),
    document_number character varying(20),
    tributary_type character varying(255) NOT NULL,
    bridge_mode character varying(20),
    endpoint_url character varying(500),
    http_method character varying(10) DEFAULT 'POST'::character varying NOT NULL,
    content_type character varying(100) DEFAULT 'application/x-www-form-urlencoded'::character varying NOT NULL,
    request_payload text NOT NULL,
    request_size_bytes integer,
    request_sha1_hash character varying(40),
    response_body text,
    response_size_bytes integer,
    http_status_code smallint,
    response_time_ms numeric(10,2),
    sunat_status character varying(50),
    sunat_code character varying(10),
    ticket_number character varying(100),
    cdr_code character varying(50),
    sunat_message text,
    request_form_data text,
    auth_scheme text,
    debug_notes text,
    error_message text,
    error_kind character varying(50),
    attempt_number smallint DEFAULT '1'::smallint NOT NULL,
    is_retry boolean DEFAULT false NOT NULL,
    is_manual_dispatch boolean DEFAULT false NOT NULL,
    initiated_by_user_id bigint,
    initiated_by_username character varying(100),
    sent_at timestamp(0) without time zone NOT NULL,
    received_at timestamp(0) without time zone,
    created_at timestamp(0) without time zone,
    updated_at timestamp(0) without time zone,
    CONSTRAINT tax_bridge_audit_logs_tributary_type_check CHECK (((tributary_type)::text = ANY ((ARRAY['SUNAT_DIRECT'::character varying, 'DETRACCION'::character varying, 'RETENCION'::character varying, 'PERCEPCION'::character varying, 'SUMMARY_RA'::character varying, 'SUMMARY_RC'::character varying, 'RESUMEN_BOLETAS'::character varying, 'REMISION_GUIA'::character varying])::text[])))
);


